4. 使用 Reducer 管理任务
创建 src/reducers/todosReducer.js：
export function todosReducer(todos, action) {
  switch (action.type) {
    case "added":
      return [
        ...todos,
        {
          id: action.id,
          text: action.text,
          completed: false,
          createdAt: action.createdAt,
        },
      ];

    case "toggled":
      return todos.map((todo) =&gt;
        todo.id === action.id
          ? { ...todo, completed: !todo.completed }
          : todo,
      );

    case "edited":
      return todos.map((todo) =&gt;
        todo.id === action.id ? { ...todo, text: action.text } : todo,
      );

    case "deleted":
      return todos.filter((todo) =&gt; todo.id !== action.id);

    case "completedCleared":
      return todos.filter((todo) =&gt; !todo.completed);

    default:
      throw new Error(`未知操作：${action.type}`);
  }
}
Reducer 只负责根据旧 State 和 Action 计算新 State，不读取 DOM、不写存储，也不直接修改原数组。

5. 实现新增表单
import { useState } from "react";

export function TodoForm({ onAdd }) {
  const [text, setText] = useState("");
  const [error, setError] = useState("");

  function handleSubmit(event) {
    event.preventDefault();
    const value = text.trim();

    if (!value) {
      setError("请输入任务内容");
      return;
    }

    onAdd(value);
    setText("");
    setError("");
  }

  return (
    &lt;form onSubmit={handleSubmit}&gt;
      &lt;label htmlFor="new-todo"&gt;新任务&lt;/label&gt;
      &lt;input
        id="new-todo"
        value={text}
        onChange={(event) =&gt; setText(event.target.value)}
        aria-describedby={error ? "todo-error" : undefined}
      /&gt;
      &lt;button type="submit"&gt;添加&lt;/button&gt;
      {error && &lt;p id="todo-error" role="alert"&gt;{error}&lt;/p&gt;}
    &lt;/form&gt;
  );
}
表单保留自己的输入和错误状态，任务数组由父组件管理。这体现了“状态放在离使用位置最近处”的原则。

6. 实现任务项
import { useState } from "react";

export function TodoItem({ todo, onToggle, onEdit, onDelete }) {
  const [isEditing, setIsEditing] = useState(false);
  const [draft, setDraft] = useState(todo.text);

  function saveEdit(event) {
    event.preventDefault();
    const value = draft.trim();

    if (value) {
      onEdit(todo.id, value);
      setIsEditing(false);
    }
  }

  if (isEditing) {
    return (
      &lt;li&gt;
        &lt;form onSubmit={saveEdit}&gt;
          &lt;label className="sr-only" htmlFor={`edit-${todo.id}`}&gt;编辑任务&lt;/label&gt;
          &lt;input
            id={`edit-${todo.id}`}
            value={draft}
            onChange={(event) =&gt; setDraft(event.target.value)}
          /&gt;
          &lt;button type="submit"&gt;保存&lt;/button&gt;
          &lt;button type="button" onClick={() =&gt; setIsEditing(false)}&gt;取消&lt;/button&gt;
        &lt;/form&gt;
      &lt;/li&gt;
    );
  }

  return (
    &lt;li&gt;
      &lt;label&gt;
        &lt;input
          type="checkbox"
          checked={todo.completed}
          onChange={() =&gt; onToggle(todo.id)}
        /&gt;
        &lt;span&gt;{todo.text}&lt;/span&gt;
      &lt;/label&gt;
      &lt;button type="button" onClick={() =&gt; setIsEditing(true)}&gt;编辑&lt;/button&gt;
      &lt;button type="button" onClick={() =&gt; onDelete(todo.id)}&gt;删除&lt;/button&gt;
    &lt;/li&gt;
  );
}
按钮明确设置 type="button"，避免它在将来被放入表单时意外触发提交。

7. 筛选与统计
export function filterTodos(todos, filter) {
  if (filter === "active") {
    return todos.filter((todo) =&gt; !todo.completed);
  }

  if (filter === "completed") {
    return todos.filter((todo) =&gt; todo.completed);
  }

  return todos;
}
在组件渲染时派生数据：
