const remainingCount = todos.filter((todo) =&gt; !todo.completed).length;
筛选按钮应让辅助技术知道当前选项：
function TodoFilters({ value, onChange }) {
  const options = [
    ["all", "全部"],
    ["active", "未完成"],
    ["completed", "已完成"],
  ];

  return (
    &lt;div aria-label="筛选任务"&gt;
      {options.map(([key, label]) =&gt; (
        &lt;button
          key={key}
          type="button"
          aria-pressed={value === key}
          onClick={() =&gt; onChange(key)}
        &gt;
          {label}
        &lt;/button&gt;
