7. 管理请求状态
搜索页需要同时管理数据和请求状态：
const [result, setResult] = useState({ books: [], total: 0 });
const [status, setStatus] = useState("idle");
const [error, setError] = useState("");

useEffect(() =&gt; {
  if (!query) {
    setResult({ books: [], total: 0 });
    setStatus("idle");
    return;
  }

  const controller = new AbortController();
  setStatus("loading");
  setError("");

  searchBooks({ query, page, signal: controller.signal })
    .then((data) =&gt; {
      setResult(data);
      setStatus("success");
    })
    .catch((requestError) =&gt; {
      if (requestError.name !== "AbortError") {
        setError("暂时无法获取图书，请稍后重试。");
        setStatus("error");
      }
    });

  return () =&gt; controller.abort();
}, [query, page]);
关键词或页码变化时，清理函数取消上一次请求。这样快速连续搜索时，较慢的旧请求不会覆盖最新结果。
根据状态渲染明确界面：
{status === "idle" && &lt;p&gt;输入关键词开始搜索。&lt;/p&gt;}
{status === "loading" && &lt;p aria-live="polite"&gt;正在搜索……&lt;/p&gt;}
{status === "error" && &lt;p role="alert"&gt;{error}&lt;/p&gt;}
{status === "success" && result.books.length === 0 && &lt;p&gt;没有找到相关图书。&lt;/p&gt;}
{status === "success" && result.books.length &gt; 0 && (
  &lt;BookGrid books={result.books} /&gt;
)}

