10. 详情页
从动态路由读取作品编号：
import { useEffect, useState } from "react";
import { Link, useParams } from "react-router";

export function BookDetailPage() {
  const { workId } = useParams();
  const [book, setBook] = useState(null);
  const [status, setStatus] = useState("loading");

  useEffect(() =&gt; {
    const controller = new AbortController();

    fetch(`https://openlibrary.org/works/${encodeURIComponent(workId)}.json`, {
      signal: controller.signal,
    })
      .then((response) =&gt; {
        if (!response.ok) throw new Error("图书不存在");
        return response.json();
      })
      .then((data) =&gt; {
        setBook(data);
        setStatus("success");
      })
      .catch((error) =&gt; {
        if (error.name !== "AbortError") setStatus("error");
      });

    return () =&gt; controller.abort();
  }, [workId]);

  if (status === "loading") return &lt;p&gt;正在加载详情……&lt;/p&gt;;
  if (status === "error") return &lt;p role="alert"&gt;无法加载图书详情。&lt;/p&gt;;

  const description = typeof book.description === "string"
    ? book.description
    : book.description?.value;

  return (
    &lt;article&gt;
      &lt;Link to="/"&gt;返回搜索&lt;/Link&gt;
      &lt;h1&gt;{book.title}&lt;/h1&gt;
      &lt;p&gt;{description || "暂无简介。"}&lt;/p&gt;
    &lt;/article&gt;
  );
}
即使用户直接刷新详情地址，页面也会根据 workId 重新请求，不依赖从列表页传来的临时 State。

11. 收藏功能
收藏数据可以保存完整的展示模型：
function useFavorites() {
  const [favorites, setFavorites] = useState(() =&gt; {
    try {
      return JSON.parse(localStorage.getItem("book-favorites")) ?? [];
    } catch {
      return [];
    }
  });

  useEffect(() =&gt; {
    localStorage.setItem("book-favorites", JSON.stringify(favorites));
  }, [favorites]);

  function toggleFavorite(book) {
    setFavorites((current) =&gt;
      current.some((item) =&gt; item.id === book.id)
        ? current.filter((item) =&gt; item.id !== book.id)
        : [...current, book],
    );
  }

  return { favorites, toggleFavorite };
}
如果搜索页、详情页和收藏页都需要它，可以把 Hook 放在 App 中，再用 Context 向下共享。

4. 安全地处理金额
JavaScript 小数计算可能产生精度误差。对日常两位小数的练习项目，可以转换为整数分：
export function yuanToCents(value) {
  const normalized = String(value).trim();

  if (!/^\d+(\.\d{1,2})?$/.test(normalized)) {
    throw new Error("金额必须是最多两位小数的正数");
  }

  const [yuan, decimal = ""] = normalized.split(".");
  return Number(yuan) * 100 + Number(decimal.padEnd(2, "0"));
}

export function formatMoney(cents) {
  return new Intl.NumberFormat("zh-CN", {
    style: "currency",
    currency: "CNY",
  }).format(cents / 100);
}
正式金融系统还要考虑币种、精度、舍入规则和后端校验，不能仅依赖这个教学示例。

5. 表单状态与校验
const initialForm = {
  type: "expense",
  amount: "",
  category: "food",
  date: new Date().toISOString().slice(0, 10),
  note: "",
};

export function TransactionForm({ onSubmit, initialValue = initialForm }) {
  const [form, setForm] = useState(initialValue);
  const [errors, setErrors] = useState({});

  function updateField(event) {
    const { name, value } = event.target;

    setForm((current) =&gt; ({
      ...current,
      [name]: value,
      ...(name === "type" ? {
        category: value === "income" ? "salary" : "food",
      } : {}),
    }));
  }

  function handleSubmit(event) {
    event.preventDefault();

    try {
      const amountInCents = yuanToCents(form.amount);
      if (amountInCents &lt;= 0) throw new Error("金额必须大于零");
      if (!form.date) throw new Error("请选择日期");

      onSubmit({
        ...form,
        amountInCents,
        note: form.note.trim(),
      });
      setForm(initialForm);
      setErrors({});
    } catch (error) {
      setErrors({ form: error.message });
    }
  }

  return (
    &lt;form onSubmit={handleSubmit}&gt;
      &lt;label&gt;
        类型
        &lt;select name="type" value={form.type} onChange={updateField}&gt;
          &lt;option value="expense"&gt;支出&lt;/option&gt;
          &lt;option value="income"&gt;收入&lt;/option&gt;
        &lt;/select&gt;
      &lt;/label&gt;

      &lt;label&gt;
        金额（元）
        &lt;input
          name="amount"
          inputMode="decimal"
          value={form.amount}
          onChange={updateField}
        /&gt;
      &lt;/label&gt;

      &lt;label&gt;
        日期
        &lt;input name="date" type="date" value={form.date} onChange={updateField} /&gt;
      &lt;/label&gt;

      &lt;label&gt;
        备注
        &lt;input name="note" maxLength="100" value={form.note} onChange={updateField} /&gt;
      &lt;/label&gt;

      {errors.form && &lt;p role="alert"&gt;{errors.form}&lt;/p&gt;}
      &lt;button type="submit"&gt;保存记录&lt;/button&gt;
    &lt;/form&gt;
  );
}
分类 &lt;select&gt; 可以根据 form.type 过滤 categories 后生成选项。

6. 使用 Reducer 管理记录
export function transactionsReducer(transactions, action) {
  switch (action.type) {
    case "added":
      return [action.transaction, ...transactions];

    case "updated":
      return transactions.map((transaction) =&gt;
        transaction.id === action.transaction.id
          ? action.transaction
          : transaction,
      );

    case "deleted":
      return transactions.filter((item) =&gt; item.id !== action.id);

    case "imported":
      return action.transactions;

    default:
      throw new Error(`未知操作：${action.type}`);
  }
}
新增记录时补齐系统字段：
dispatch({
  type: "added",
  transaction: {
    ...formData,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  },
});

7. 筛选交易
筛选条件可以集中在一个对象中：
const initialFilters = {
  month: "all",
  type: "all",
  category: "all",
};
纯函数负责筛选：
export function filterTransactions(transactions, filters) {
  return transactions.filter((transaction) =&gt; {
    const matchesMonth = filters.month === "all"
      || transaction.date.startsWith(filters.month);
    const matchesType = filters.type === "all"
      || transaction.type === filters.type;
    const matchesCategory = filters.category === "all"
      || transaction.category === filters.category;

    return matchesMonth && matchesType && matchesCategory;
  });
}
月份值可以使用 2026-07。修改类型后，如果当前分类不再适用，应把分类重置为 all。

8. 计算收入、支出与余额
export function summarizeTransactions(transactions) {
  return transactions.reduce(
    (summary, transaction) =&gt; {
      if (transaction.type === "income") {
        summary.income += transaction.amountInCents;
      } else {
        summary.expense += transaction.amountInCents;
      }

      summary.balance = summary.income - summary.expense;
      return summary;
    },
    { income: 0, expense: 0, balance: 0 },
  );
}
在组件中对筛选后的记录计算：
const visibleTransactions = filterTransactions(transactions, filters);
const summary = summarizeTransactions(visibleTransactions);
这样卡片显示的是当前筛选范围的汇总。界面需要明确标注“当前筛选”，避免用户误以为它表示所有数据。

9. 分类汇总与图表
export function summarizeExpensesByCategory(transactions) {
  return transactions
    .filter((item) =&gt; item.type === "expense")
    .reduce((result, item) =&gt; ({
      ...result,
      [item.category]: (result[item.category] ?? 0) + item.amountInCents,
    }), {});
}
初学阶段不必立即安装图表库。可以先用 CSS 宽度展示水平条形图：
function CategoryChart({ data }) {
  const entries = Object.entries(data);
  const maximum = Math.max(...entries.map(([, amount]) =&gt; amount), 0);

  if (entries.length === 0) return &lt;p&gt;暂无支出数据。&lt;/p&gt;;

  return (
    &lt;div aria-label="支出分类统计"&gt;
      {entries.map(([category, amount]) =&gt; (
        &lt;div key={category}&gt;
          &lt;span&gt;{categories[category].label}&lt;/span&gt;
          &lt;div
            className="chart-bar"
            style={{ width: `${(amount / maximum) * 100}%` }}
          /&gt;
          &lt;span&gt;{formatMoney(amount)}&lt;/span&gt;
        &lt;/div&gt;
      ))}
    &lt;/div&gt;
  );
}
颜色不能作为唯一信息来源，同时显示分类名称和金额。

10. 本地保存与数据版本
建议保存带版本的对象，而不是直接保存数组：
const storageValue = {
  version: 1,
  transactions,
};

localStorage.setItem("expense-tracker", JSON.stringify(storageValue));
读取时验证基本结构：
function readTransactions() {
  try {
    const raw = localStorage.getItem("expense-tracker");
    if (!raw) return [];

    const data = JSON.parse(raw);
    if (data.version !== 1 || !Array.isArray(data.transactions)) return [];
    return data.transactions.filter(isValidTransaction);
  } catch {
    return [];
  }
}
数据版本为以后迁移字段留下空间。isValidTransaction 应检查编号、类型、整数金额、日期和分类，而不是盲目信任本地数据。

13. 测试策略
纯函数最容易测试：
it("正确计算收入、支出和余额", () =&gt; {
  const result = summarizeTransactions([
    { type: "income", amountInCents: 100000 },
    { type: "expense", amountInCents: 2580 },
  ]);

  expect(result).toEqual({
    income: 100000,
    expense: 2580,
    balance: 97420,
  });
});
组件流程还应覆盖：

无效金额显示错误
新增记录后列表和汇总同时更新
筛选月份后只显示匹配记录
编辑保持编号不变
删除后记录消失
损坏的存储数据不会让应用崩溃

3 变量：const 与 let
现代 JavaScript 主要使用 const 和 let 声明变量。
const courseName = "React 入门";
let currentLesson = 1;

currentLesson = 2;

const 声明的变量不能重新赋值
let 声明的变量可以重新赋值
默认优先使用 const，确实需要重新赋值时才使用 let







注记const 不等于完全不可变



const 只表示变量不能指向另一个值。对象内部的属性仍然可能被修改。


const user = { name: "小明" };

user.name = "小红"; // 可以执行，但 React 中通常不这样更新状态
// user = { name: "小红" }; // 报错：不能重新赋值
在 React 中更新对象或数组状态时，通常要创建一个新值，而不是直接修改旧值。这一点会在展开运算符部分继续讲解。

5 函数、箭头函数与回调函数
函数把一段可以重复使用的逻辑封装起来。

5.1 普通函数
function formatPrice(price) {
  return `¥${price.toFixed(2)}`;
}

console.log(formatPrice(299)); // "¥299.00"
price 是参数，return 后面的内容是函数返回值。


5.2 箭头函数
箭头函数是 React 代码中非常常见的写法：
const formatPrice = (price) =&gt; {
  return `¥${price.toFixed(2)}`;
};
函数体只有一个返回表达式时，可以进一步简写：
const formatPrice = (price) =&gt; `¥${price.toFixed(2)}`;
返回对象时，需要用圆括号包住对象：
const createProduct = (name, price) =&gt; ({
  name,
  price,
  inStock: true,
});


5.3 回调函数
把一个函数作为参数传给另一个函数，这个函数就叫回调函数。
const names = products.map((product) =&gt; product.name);
这里传给 map 的箭头函数就是回调函数。map 会为每个商品调用一次它。
React 的点击事件也会接收回调函数：
function SaveButton() {
  const handleClick = () =&gt; {
    console.log("保存成功");
  };

  return &lt;button onClick={handleClick}&gt;保存&lt;/button&gt;;
}
注意传递的是函数 handleClick，不是立即执行后的结果 handleClick()。

6 条件判断与逻辑运算符

6.1 if 判断
function getStockText(product) {
  if (product.inStock) {
    return "有货";
  }

  return "缺货";
}


6.2 三元运算符
三元运算符适合根据一个条件在两个值之间选择：
const stockText = product.inStock ? "有货" : "缺货";
在 JSX 中经常使用它：
&lt;span&gt;{product.inStock ? "有货" : "缺货"}&lt;/span&gt;


6.3 逻辑与 &&
只希望条件成立时显示内容，可以使用 &&：
{product.inStock && &lt;button&gt;加入购物车&lt;/button&gt;}


6.4 空值合并 ??
当左侧是 null 或 undefined 时，使用右侧默认值：
const displayName = user.nickname ?? "未设置昵称";
它与 || 不完全相同。|| 还会把 0、空字符串和 false 当成需要使用默认值的情况。

7 数组常用方法
React 经常需要把数组转换为组件列表，或者根据条件生成一个新数组。下面这些方法非常重要。

7.1 map：转换每一项
map 会返回一个长度相同的新数组。
const names = products.map((product) =&gt; product.name);

console.log(names); // ["键盘", "鼠标", "显示器"]
React 使用 map 渲染列表：
function ProductList() {
  return (
    &lt;ul&gt;
      {products.map((product) =&gt; (
        &lt;li key={product.id}&gt;
          {product.name}：¥{product.price}
        &lt;/li&gt;
      ))}
    &lt;/ul&gt;
  );
}


7.2 filter：筛选数据
filter 保留回调函数返回 true 的元素。
const availableProducts = products.filter(
  (product) =&gt; product.inStock
);
删除一项数据时也常使用 filter：
const remainingProducts = products.filter(
  (product) =&gt; product.id !== 2
);


7.3 find：找到一项
find 返回第一个符合条件的元素；找不到时返回 undefined。
const product = products.find((product) =&gt; product.id === 2);

console.log(product?.name); // "鼠标"
?. 是可选链。左侧为 null 或 undefined 时，它会返回 undefined，避免继续访问属性导致报错。


7.4 some：判断是否存在
只需要知道是否至少有一项符合条件时，使用 some：
const hasExpensiveProduct = products.some(
  (product) =&gt; product.price &gt; 1000
);

console.log(hasExpensiveProduct); // true


7.5 reduce：累计计算
reduce 可以把一个数组汇总为一个值：
const totalPrice = products.reduce(
  (total, product) =&gt; total + product.price,
  0
);

console.log(totalPrice); // 2027
这里的 0 是累计值 total 的初始值。第一次执行回调时，total 为 0。






提示如何选择数组方法




每一项都要转换：使用 map
筛选出多项：使用 filter
查找某一项：使用 find
判断是否存在：使用 some
汇总为一个结果：使用 reduce

8 解构赋值
解构可以从对象或数组中快速取出需要的值。

8.1 对象解构
const product = {
  id: 1,
  name: "键盘",
  price: 299,
};

const { name, price } = product;

console.log(name);  // "键盘"
console.log(price); // 299
React 组件经常直接解构 Props：
function ProductCard({ name, price, inStock }) {
  return (
    &lt;article&gt;
      &lt;h2&gt;{name}&lt;/h2&gt;
      &lt;p&gt;¥{price}&lt;/p&gt;
      &lt;p&gt;{inStock ? "有货" : "缺货"}&lt;/p&gt;
    &lt;/article&gt;
  );
}
可以设置默认值，也可以给属性换一个变量名：
const { name: productName, discount = 0 } = product;


8.2 数组解构
const colors = ["红色", "绿色", "蓝色"];
const [firstColor, secondColor] = colors;
React 的 useState 就使用了数组解构：
const [count, setCount] = useState(0);

9 展开运算符
展开运算符 ... 可以把数组元素或对象属性展开到一个新值中。

9.1 复制并更新数组
const newProduct = {
  id: 4,
  name: "耳机",
  price: 399,
  inStock: true,
};

const nextProducts = [...products, newProduct];


9.2 复制并更新对象
const product = products[0];

const updatedProduct = {
  ...product,
  price: 259,
};
后面的 price 会覆盖前面展开出来的旧 price。


9.3 更新数组中的某个对象
const nextProducts = products.map((product) =&gt;
  product.id === 1
    ? { ...product, price: 259 }
    : product
);
这种写法没有修改原数组和原对象，而是生成了新数组，并为需要变化的商品创建新对象。这是更新 React State 的常用方式。






重要避免直接修改 React State



不要使用 products.push(...) 或直接写 product.price = 259 来更新 State。React 通常依靠新旧值的引用变化判断是否需要重新渲染。

10 模块化：export 与 import
模块化可以把代码拆分到不同文件中。

10.1 命名导出
// utils.js
export const formatPrice = (price) =&gt; `¥${price.toFixed(2)}`;

export const isExpensive = (price) =&gt; price &gt; 1000;
导入时使用相同名称和花括号：
// ProductCard.jsx
import { formatPrice, isExpensive } from "./utils.js";


10.2 默认导出
// ProductCard.jsx
export default function ProductCard() {
  return &lt;article&gt;商品卡片&lt;/article&gt;;
}
默认导入不使用花括号，名称可以自行决定：
import ProductCard from "./ProductCard.jsx";
一个模块只能有一个默认导出，但可以有多个命名导出。

11 Promise、async/await 与 fetch
浏览器请求接口需要时间，JavaScript 不会停下来一直等待，而是使用 Promise 表示“将来才会得到的结果”。

11.1 使用 async/await
async function loadProducts() {
  const response = await fetch("https://example.com/api/products");

  if (!response.ok) {
    throw new Error(`请求失败：${response.status}`);
  }

  const data = await response.json();
  return data;
}

async 表示函数会返回 Promise
await 等待 Promise 完成并取得结果
response.ok 用来判断 HTTP 状态是否成功
response.json() 也是异步操作，因此也需要 await



11.2 处理错误
async function showProducts() {
  try {
    const products = await loadProducts();
    console.log(products);
  } catch (error) {
    console.error("加载商品失败", error);
  }
}
在 React 中，通常要分别保存加载、成功和失败状态：
const [products, setProducts] = useState([]);
const [isLoading, setIsLoading] = useState(true);
const [error, setError] = useState(null);
具体如何在组件中发起请求，会在学习 useEffect 时继续讲解。

12 DOM、事件与 React 的区别
使用原生 JavaScript 时，我们会主动查找并修改 DOM：
const button = document.querySelector("#counter-button");
const result = document.querySelector("#result");
let count = 0;

button.addEventListener("click", () =&gt; {
  count += 1;
  result.textContent = count;
});
React 更关注“当前数据应该对应什么界面”：
function Counter() {
  const [count, setCount] = useState(0);

  return (
    &lt;div&gt;
      &lt;p&gt;{count}&lt;/p&gt;
      &lt;button onClick={() =&gt; setCount(count + 1)}&gt;增加&lt;/button&gt;
    &lt;/div&gt;
  );
}
点击按钮后，我们更新 count，React 根据新的 count 重新生成界面。通常不需要自己调用 querySelector 或修改 textContent。
事件名称也有一些区别：



原生 HTML / DOM
React JSX




onclick
onClick


onchange
onChange


class
className


传入字符串代码
传入 JavaScript 函数

