添加 BrowserRouter
// main.jsx
import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { BrowserRouter } from "react-router";
import App from "./App.jsx";

createRoot(document.getElementById("root")).render(
  &lt;StrictMode&gt;
    &lt;BrowserRouter&gt;
      &lt;App /&gt;
    &lt;/BrowserRouter&gt;
  &lt;/StrictMode&gt;
);
路由 Hooks 和组件必须位于 Router 内部。

配置页面路由
// App.jsx
import { Route, Routes } from "react-router";
import HomePage from "./pages/HomePage.jsx";
import ProductListPage from "./pages/ProductListPage.jsx";
import ProductDetailPage from "./pages/ProductDetailPage.jsx";
import NotFoundPage from "./pages/NotFoundPage.jsx";

export default function App() {
  return (
    &lt;Routes&gt;
      &lt;Route path="/" element={&lt;HomePage /&gt;} /&gt;
      &lt;Route path="/products" element={&lt;ProductListPage /&gt;} /&gt;
      &lt;Route path="/products/:productId" element={&lt;ProductDetailPage /&gt;} /&gt;
      &lt;Route path="*" element={&lt;NotFoundPage /&gt;} /&gt;
    &lt;/Routes&gt;
  );
}
Route 根据当前 URL 选择 element。

Link 与 NavLink
应用内导航使用 Link，避免普通 &lt;a&gt; 触发完整文档重新加载：
import { Link } from "react-router";

&lt;Link to="/products"&gt;查看商品&lt;/Link&gt;
导航栏使用 NavLink 获取活动状态：
import { NavLink } from "react-router";

function MainNav() {
  return (
    &lt;nav aria-label="主导航"&gt;
      &lt;NavLink
        to="/"
        className={({ isActive }) =&gt; isActive ? "active" : ""}
      &gt;
        首页
      &lt;/NavLink&gt;
      &lt;NavLink to="/products"&gt;商品&lt;/NavLink&gt;
    &lt;/nav&gt;
  );
}
外部网站、文件下载和邮箱地址仍使用普通 a。

编程式导航
提交成功后跳转：
import { useNavigate } from "react-router";

function CreateProductForm() {
  const navigate = useNavigate();

  async function handleSubmit(event) {
    event.preventDefault();
    const product = await createProduct();
    navigate(`/products/${product.id}`);
  }

  return &lt;form onSubmit={handleSubmit}&gt;...&lt;/form&gt;;
}
普通导航优先使用 Link，它提供更好的链接语义。只有事件完成后跳转等场景才使用 useNavigate。
返回上一页：
navigate(-1);

动态路由参数
路由中的 :productId 是动态段：
&lt;Route path="/products/:productId" element={&lt;ProductDetailPage /&gt;} /&gt;
页面读取参数：
import { useParams } from "react-router";

function ProductDetailPage() {
  const { productId } = useParams();
  return &lt;h1&gt;商品编号：{productId}&lt;/h1&gt;;
}
参数来自 URL，通常是字符串。用于数组查找或请求前要验证和转换。

查询参数
列表筛选适合使用查询参数：
/products?query=keyboard&sort=price
import { useSearchParams } from "react-router";

function ProductListPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const query = searchParams.get("query") ?? "";
  const sort = searchParams.get("sort") ?? "default";

  function updateQuery(nextQuery) {
    setSearchParams((current) =&gt; {
      const next = new URLSearchParams(current);
      if (nextQuery) next.set("query", nextQuery);
      else next.delete("query");
      return next;
    });
  }

  return &lt;SearchForm query={query} onQueryChange={updateQuery} /&gt;;
}
把筛选条件放入 URL，可以刷新、分享并使用浏览器历史。

嵌套路由与公共布局
import { Outlet } from "react-router";

function RootLayout() {
  return (
    &lt;&gt;
      &lt;Header /&gt;
      &lt;main&gt;&lt;Outlet /&gt;&lt;/main&gt;
      &lt;Footer /&gt;
    &lt;/&gt;
  );
}
&lt;Routes&gt;
  &lt;Route element={&lt;RootLayout /&gt;}&gt;
    &lt;Route index element={&lt;HomePage /&gt;} /&gt;
    &lt;Route path="products"&gt;
      &lt;Route index element={&lt;ProductListPage /&gt;} /&gt;
      &lt;Route path=":productId" element={&lt;ProductDetailPage /&gt;} /&gt;
    &lt;/Route&gt;
    &lt;Route path="*" element={&lt;NotFoundPage /&gt;} /&gt;
  &lt;/Route&gt;
&lt;/Routes&gt;

Outlet 是匹配子路由的显示位置
index 是父路径的默认子页面
子路由路径通常使用相对写法

404 页面
function NotFoundPage() {
  return (
    &lt;main&gt;
      &lt;h1&gt;页面不存在&lt;/h1&gt;
      &lt;p&gt;请检查地址，或返回首页。&lt;/p&gt;
      &lt;Link to="/"&gt;返回首页&lt;/Link&gt;
    &lt;/main&gt;
  );
}
path="*" 捕获未匹配路径。数据找不到与路由找不到是不同问题，详情页也要处理不存在的商品。

事件处理
React 事件使用驼峰命名并接收函数：
function SaveButton() {
  function handleClick() {
    console.log("保存成功");
  }

  return &lt;button onClick={handleClick}&gt;保存&lt;/button&gt;;
}
传递函数，不要立即调用：
// 正确
&lt;button onClick={handleClick}&gt;保存&lt;/button&gt;

// 错误：渲染时立即执行
&lt;button onClick={handleClick()}&gt;保存&lt;/button&gt;
需要参数时包一层箭头函数：
&lt;button onClick={() =&gt; deleteProduct(product.id)}&gt;删除&lt;/button&gt;

事件对象
function SearchForm() {
  function handleSubmit(event) {
    event.preventDefault();
    console.log("提交搜索");
  }

  return &lt;form onSubmit={handleSubmit}&gt;...&lt;/form&gt;;
}
不要只监听提交按钮点击，表单的 onSubmit 同时支持键盘回车。


阻止冒泡
function DeleteButton() {
  return (
    &lt;button
      onClick={(event) =&gt; {
        event.stopPropagation();
        console.log("删除");
      }}
    &gt;
      删除
    &lt;/button&gt;
  );
}
只在确实需要时阻止冒泡，避免破坏父级交互。

useState
import { useState } from "react";

function Counter() {
  const [count, setCount] = useState(0);

  return (
    &lt;button onClick={() =&gt; setCount(count + 1)}&gt;
      点击了 {count} 次
    &lt;/button&gt;
  );
}

count：当前渲染中的 State
setCount：请求 React 使用新值重新渲染
0：初始值

Hooks 必须在组件或自定义 Hook 顶层调用，不能放在条件、循环或普通嵌套函数中。

State 是一次渲染的快照
调用更新函数不会修改当前事件函数中已经取得的 count：
function handleClick() {
  setCount(count + 1);
  console.log(count); // 仍是当前渲染的值
}
React 会安排下一次渲染，新渲染获得新的 State。

基于前一个值更新
function handleAddThree() {
  setCount((current) =&gt; current + 1);
  setCount((current) =&gt; current + 1);
  setCount((current) =&gt; current + 1);
}
当新值依赖前一个值时，使用函数式更新最清晰。

State 应保持最小
能从现有 Props 或 State 计算出的数据，不要重复保存：
const [firstName, setFirstName] = useState("");
const [lastName, setLastName] = useState("");

const fullName = `${firstName} ${lastName}`.trim();
重复状态容易不同步。

更新对象
不要直接修改：
// 错误
user.name = "小红";
setUser(user);
创建新对象：
setUser((current) =&gt; ({
  ...current,
  name: "小红",
}));
通用输入处理：
function handleChange(event) {
  const { name, value } = event.target;

  setForm((current) =&gt; ({
    ...current,
    [name]: value,
  }));
}

更新数组

添加
setTodos((current) =&gt; [...current, newTodo]);


删除
setTodos((current) =&gt;
  current.filter((todo) =&gt; todo.id !== todoId)
);


更新其中一项
setTodos((current) =&gt;
  current.map((todo) =&gt;
    todo.id === todoId
      ? { ...todo, completed: !todo.completed }
      : todo
  )
);
避免对 State 数组直接使用 push、splice 或原地 sort。

受控表单
function LoginForm() {
  const [form, setForm] = useState({ email: "", password: "" });
  const [error, setError] = useState("");

  function handleChange(event) {
    const { name, value } = event.target;
    setForm((current) =&gt; ({ ...current, [name]: value }));
  }

  function handleSubmit(event) {
    event.preventDefault();

    if (!form.email.includes("@")) {
      setError("请输入有效邮箱");
      return;
    }

    if (form.password.length &lt; 8) {
      setError("密码至少需要 8 个字符");
      return;
    }

    setError("");
    console.log("提交", form);
  }

  return (
    &lt;form onSubmit={handleSubmit} noValidate&gt;
      &lt;label htmlFor="email"&gt;邮箱&lt;/label&gt;
      &lt;input
        id="email"
        name="email"
        type="email"
        value={form.email}
        onChange={handleChange}
      /&gt;

      &lt;label htmlFor="password"&gt;密码&lt;/label&gt;
      &lt;input
        id="password"
        name="password"
        type="password"
        value={form.password}
        onChange={handleChange}
      /&gt;

      {error && &lt;p role="alert"&gt;{error}&lt;/p&gt;}
      &lt;button type="submit"&gt;登录&lt;/button&gt;
    &lt;/form&gt;
  );
}
输入框的 value 来自 State，onChange 更新 State，这就是受控输入。

状态提升
两个组件需要共享同一数据时，把 State 移到它们最近的共同父组件：
function ProductPage() {
  const [query, setQuery] = useState("");

  return (
    &lt;&gt;
      &lt;SearchInput value={query} onChange={setQuery} /&gt;
      &lt;ProductList query={query} /&gt;
    &lt;/&gt;
  );
}
function SearchInput({ value, onChange }) {
  return (
    &lt;input
      value={value}
      onChange={(event) =&gt; onChange(event.target.value)}
    /&gt;
  );
}
父组件拥有状态，通过 Props 向下传数据和更新函数，这体现单向数据流。

综合练习：待办事项
实现以下功能：

添加任务
标记完成
删除任务
按全部、未完成、已完成筛选
显示剩余数量
阻止空白任务

建议状态：
const [todos, setTodos] = useState([]);
const [title, setTitle] = useState("");
const [filter, setFilter] = useState("all");
可见任务应由现有 State 计算，不要额外保存：
const visibleTodos = todos.filter((todo) =&gt; {
  if (filter === "active") return !todo.completed;
  if (filter === "completed") return todo.completed;
  return true;
});

1. 局部状态与共享状态
只被一个组件使用的数据，优先放在该组件中：
import { useState } from "react";

function SearchBox() {
  const [keyword, setKeyword] = useState("");

  return (
    &lt;input
      value={keyword}
      onChange={(event) =&gt; setKeyword(event.target.value)}
      placeholder="搜索商品"
    /&gt;
  );
}
如果两个兄弟组件需要同一份状态，把状态提升到它们最近的共同父组件，再通过 Props 向下传递：
function ProductPage() {
  const [keyword, setKeyword] = useState("");

  return (
    &lt;&gt;
      &lt;SearchInput value={keyword} onChange={setKeyword} /&gt;
      &lt;ProductList keyword={keyword} /&gt;
    &lt;/&gt;
  );
}
“全局状态”不是指必须使用某个状态库，而是指多个相距较远的组件都需要访问的数据，例如当前用户、主题和语言。

3. 使用 Context 跨层共享数据
Context 可以让后代组件读取共同数据，避免逐层转发 Props。
import { createContext, useContext, useState } from "react";

const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState("light");

  function toggleTheme() {
    setTheme((current) =&gt; (current === "light" ? "dark" : "light"));
  }

  return (
    &lt;ThemeContext.Provider value={{ theme, toggleTheme }}&gt;
      {children}
    &lt;/ThemeContext.Provider&gt;
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);

  if (context === null) {
    throw new Error("useTheme 必须在 ThemeProvider 内使用");
  }

  return context;
}
在应用入口包裹 Provider：
&lt;ThemeProvider&gt;
  &lt;App /&gt;
&lt;/ThemeProvider&gt;
后代组件可以直接读取：
function ThemeButton() {
  const { theme, toggleTheme } = useTheme();

  return &lt;button onClick={toggleTheme}&gt;当前主题：{theme}&lt;/button&gt;;
}
Context 适合低频变化、使用范围广的数据。不要仅仅为了少传一层 Props 就使用它。

4. 使用 useReducer 管理复杂更新
当同一份状态有多种更新动作，或者新状态依赖旧状态时，可以把更新规则集中到 Reducer 中。
import { useReducer } from "react";

function tasksReducer(tasks, action) {
  switch (action.type) {
    case "added":
      return [
        ...tasks,
        { id: action.id, text: action.text, done: false },
      ];
    case "toggled":
      return tasks.map((task) =&gt;
        task.id === action.id ? { ...task, done: !task.done } : task,
      );
    case "deleted":
      return tasks.filter((task) =&gt; task.id !== action.id);
    default:
      throw new Error(`未知操作：${action.type}`);
  }
}

function TodoApp() {
  const [tasks, dispatch] = useReducer(tasksReducer, []);

  function addTask(text) {
    dispatch({ type: "added", id: crypto.randomUUID(), text });
  }

  return &lt;TodoList tasks={tasks} onAdd={addTask} dispatch={dispatch} /&gt;;
}
Reducer 必须保持纯粹：相同输入应得到相同输出，不应直接修改原数组，也不应在 Reducer 内发送请求。

5. Context 与 Reducer 组合
大型组件树可以通过两个 Context 分别共享状态和操作函数：
const TasksContext = createContext(null);
const TasksDispatchContext = createContext(null);

function TasksProvider({ children }) {
  const [tasks, dispatch] = useReducer(tasksReducer, []);

  return (
    &lt;TasksContext.Provider value={tasks}&gt;
      &lt;TasksDispatchContext.Provider value={dispatch}&gt;
        {children}
      &lt;/TasksDispatchContext.Provider&gt;
    &lt;/TasksContext.Provider&gt;
  );
}
这样，展示列表的组件只读取 TasksContext，按钮组件只读取 TasksDispatchContext。更新规则仍集中在 Reducer 中。

7. memo、useMemo 与 useCallback

memo
memo 可以在 Props 没有变化时跳过子组件重新渲染：
import { memo } from "react";

const ProductRow = memo(function ProductRow({ product }) {
  return &lt;li&gt;{product.name}&lt;/li&gt;;
});
它更适合渲染成本明显、Props 又经常保持不变的组件。


useMemo
useMemo 缓存一次计算结果：
const visibleProducts = useMemo(
  () =&gt; filterProducts(products, keyword),
  [products, keyword],
);
普通的筛选和计算通常很快。只有计算确实昂贵，或稳定引用对其他优化有帮助时，才需要它。


useCallback
useCallback 缓存函数引用：
const handleSelect = useCallback((id) =&gt; {
  setSelectedId(id);
}, []);
它常与 memo 组件配合。单独给所有函数套上 useCallback，可能增加复杂度却没有实际收益。

从页面识别组件
一个商品搜索页面可以拆成：
App
├── Header
├── SearchForm
├── ProductList
│   ├── ProductCard
│   ├── ProductCard
│   └── ProductCard
└── Footer
对应 JSX：
function App() {
  return (
    &lt;&gt;
      &lt;Header /&gt;
      &lt;main&gt;
        &lt;SearchForm /&gt;
        &lt;ProductList /&gt;
      &lt;/main&gt;
      &lt;Footer /&gt;
    &lt;/&gt;
  );
}
这棵结构称为组件树。父组件包含子组件，子组件还可以继续包含其他组件。

什么适合成为组件
遇到以下情况时，可以考虑拆分组件：

页面中重复出现相同结构
一部分界面具有明确名称和职责
一段代码包含相对独立的交互
组件已经太长，难以快速理解
某部分需要单独测试或复用

例如多次出现的商品卡片很适合成为组件：
function ProductCard({ name, price, inStock }) {
  return (
    &lt;article className="product-card"&gt;
      &lt;h2&gt;{name}&lt;/h2&gt;
      &lt;p&gt;¥{price}&lt;/p&gt;
      &lt;p&gt;{inStock ? "有货" : "缺货"}&lt;/p&gt;
    &lt;/article&gt;
  );
}

组件通过数据复用
同一个结构可以接收不同数据：
function ProductList({ products }) {
  return (
    &lt;section className="product-grid"&gt;
      {products.map((product) =&gt; (
        &lt;ProductCard
          key={product.id}
          name={product.name}
          price={product.price}
          inStock={product.inStock}
        /&gt;
      ))}
    &lt;/section&gt;
  );
}
组件不应该把每件商品写死在内部，而是通过 Props 接收数据。

组合优于巨型组件
巨型组件把所有内容放在一个函数中：
function App() {
  // 搜索、筛选、商品列表、弹窗、页脚等全部代码
}
随着功能增长，它会变得难以阅读。组合后的 App 更像页面结构说明：
function App() {
  return (
    &lt;PageLayout&gt;
      &lt;SearchForm /&gt;
      &lt;ProductList /&gt;
    &lt;/PageLayout&gt;
  );
}

不要过度拆分
下面这种组件通常没有提供明显价值：
function ProductName({ name }) {
  return &lt;span&gt;{name}&lt;/span&gt;;
}
如果它只使用一次、没有独立行为，也不表达重要概念，直接写 &lt;span&gt;{name}&lt;/span&gt; 可能更清晰。






提示初学阶段的拆分顺序



先写出可以工作的页面，再观察重复结构和职责边界。不要在还不了解页面需求时提前创建大量只有一两行的组件。

组件名和文件名
React 组件名必须以大写字母开头：
function ProductCard() {
  return &lt;article&gt;商品&lt;/article&gt;;
}
小写名称会被当作 HTML 标签：
// React 会把 productCard 当成未知 HTML 标签
function productCard() {
  return &lt;article&gt;商品&lt;/article&gt;;
}
常见做法是组件文件也使用相同名称：
components/
├── Header.jsx
├── ProductCard.jsx
└── ProductList.jsx

命令式 DOM 操作
使用原生 JavaScript 编写计数器时，我们可以主动查找和修改 DOM：
&lt;p id="count"&gt;0&lt;/p&gt;
&lt;button id="add-button" type="button"&gt;增加&lt;/button&gt;
const countElement = document.querySelector("#count");
const button = document.querySelector("#add-button");

let count = 0;

button.addEventListener("click", () =&gt; {
  count += 1;
  countElement.textContent = count;
});
这段代码明确告诉浏览器：

找到计数元素
找到按钮
监听点击
修改变量
修改 DOM 文字

这是一种命令式思路。

声明式计数器
React 版本更关注数据与界面的对应关系：
import { useState } from "react";

function Counter() {
  const [count, setCount] = useState(0);

  return (
    &lt;section&gt;
      &lt;p&gt;当前数量：{count}&lt;/p&gt;
      &lt;button onClick={() =&gt; setCount(count + 1)}&gt;
        增加
      &lt;/button&gt;
    &lt;/section&gt;
  );
}
点击按钮时，我们更新 count。React 根据新的 count 重新计算组件界面，并完成必要的 DOM 更新。
用户点击
   ↓
更新数据 count
   ↓
组件重新计算 JSX
   ↓
React 更新必要的 DOM

用状态描述界面
假设一个提交按钮存在两种状态：



数据状态
按钮文字
是否禁用




isSubmitting = false
提交
否


isSubmitting = true
提交中……
是



JSX 可以直接表达这个关系：
function SubmitButton({ isSubmitting }) {
  return (
    &lt;button disabled={isSubmitting}&gt;
      {isSubmitting ? "提交中……" : "提交"}
    &lt;/button&gt;
  );
}
不需要分别编写“把文字改为提交中”“禁用按钮”“恢复按钮”这些 DOM 步骤。

多种页面状态
数据请求页面通常至少包含四种状态：

加载中
加载失败
空数据
加载成功

可以将它们清晰地写成条件：
function ProductList({ products, isLoading, error }) {
  if (isLoading) {
    return &lt;p&gt;正在加载商品……&lt;/p&gt;;
  }

  if (error) {
    return &lt;p role="alert"&gt;商品加载失败&lt;/p&gt;;
  }

  if (products.length === 0) {
    return &lt;p&gt;暂时没有商品&lt;/p&gt;;
  }

  return (
    &lt;ul&gt;
      {products.map((product) =&gt; (
        &lt;li key={product.id}&gt;{product.name}&lt;/li&gt;
      ))}
    &lt;/ul&gt;
  );
}
每个数据状态都有明确的界面结果。

数据应该是界面的事实来源
如果按钮是否禁用由 isSubmitting 决定，就不要再额外维护一个独立变量表示按钮状态，否则两个值可能不一致。
// 推荐：直接从已有状态得到结果
const buttonText = isSubmitting ? "提交中……" : "提交";
能从已有数据计算出来的值，通常不需要保存为额外状态。

最小 React 组件
下面的函数就是一个 React 组件：
function Welcome() {
  return &lt;h1&gt;欢迎学习 React&lt;/h1&gt;;
}
这个函数返回的内容看起来像 HTML，但它实际上是 JSX。构建工具会把 JSX 转换成浏览器能够执行的 JavaScript。
组件可以接收数据：
function Welcome({ name }) {
  return &lt;h1&gt;欢迎你，{name}&lt;/h1&gt;;
}
使用组件时，可以传入不同数据：
function App() {
  return (
    &lt;main&gt;
      &lt;Welcome name="小明" /&gt;
      &lt;Welcome name="小红" /&gt;
    &lt;/main&gt;
  );
}
React 主要关心两件事：

当前数据应该对应什么界面
数据变化后，哪些界面需要更新

React 不会替代什么
React 不会替代 HTML、CSS 和 JavaScript。

组件仍然使用 HTML 语义组织内容
页面仍然使用 CSS 控制样式和布局
数据处理、函数和异步请求仍然是 JavaScript
浏览器最终显示的仍然是 DOM

React 改变的是我们组织界面和处理更新的方式。
function ProductCard({ product }) {
  return (
    &lt;article className="product-card"&gt;
      &lt;h2&gt;{product.name}&lt;/h2&gt;
      &lt;p&gt;¥{product.price}&lt;/p&gt;
      &lt;button type="button"&gt;加入购物车&lt;/button&gt;
    &lt;/article&gt;
  );
}
这段代码同时使用了：

HTML 语义：article、h2、p、button
CSS 类：product-card
JavaScript：参数、对象属性和表达式
React：组件和 JSX

React 适合解决的问题
React 特别适合界面由数据驱动、交互较多或需要复用大量界面结构的项目，例如：

管理后台
电商购物流程
即时通信界面
在线编辑器
数据看板
具有复杂表单的业务应用
需要跨页面复用组件的产品

一个商品列表中，每张卡片结构相同、数据不同，就非常适合组件化：
function ProductList({ products }) {
  return (
    &lt;section&gt;
      {products.map((product) =&gt; (
        &lt;ProductCard key={product.id} product={product} /&gt;
      ))}
    &lt;/section&gt;
  );
}
